module freq_div (
    CLK_in,
    RST,
    CLK_50,
    CLK_10,
    CLK_1
);
    input CLK_in;
    input RST;
    output CLK_50;
    output CLK_10;
    output CLK_1;

    reg [1:0] count_50;
    reg [3:0] count_10;
    reg [6:0] count_1;

    always @(posedge CLK_in or posedge RST) begin
        if (RST) begin
            count_50 <= 2'b00;
            count_10 <= 4'b0000;
            count_1  <= 7'b0000000;
        end
        else begin
            count_50 <= count_50 + 1;
            count_10 <= count_10 + 1;
            count_1  <= count_1 + 1;
        end
    end

    assign CLK_50 = count_50[0];
    assign CLK_10 = count_10[0];
    assign CLK_1  = count_1[0];

endmodule
